<template>
    <view class="contain">
        <view class="title">
            <view>
                誕生月を選択
            </view>
            <view class="fu">
                ※複数選択可
            </view>
        </view>
        <view class="content">
            <view class="item" v-for="(item,index) in array"  @click="changeTab(index)">
                <view class="itemLeft">
                    <view class="unselect" v-if="!item.checked"></view>
                    <view class="selected" v-if="item.checked">
                        <view class="fill"></view>
                    </view>
                </view>
                <view class="itemRight" :style="item.checked? 'color:#1D1D1F;' : 'color: #AAAAAA' " v-text="`${item.value}月`"></view>
            </view>
        </view>
    </view>
</template>

<script>
    export default {
        data() {
            return {
                current:0,
                array:[
                    {
                        value:"1",
                        checked:false
                    },
                    {
                        value:"2",
                        checked:false
                    },
                    {
                        value:"3",
                        checked:false
                    },
                    {
                        value:"4",
                        checked:false
                    },
                    {
                        value:"5",
                        checked:false
                    },
                    {
                        value:"6",
                        checked:false
                    },
                    {
                        value:"7",
                        checked:false
                    },
                    {
                        value:"8",
                        checked:false
                    },
                    {
                        value:"9",
                        checked:false
                    },
                    {
                        value:"10",
                        checked:false
                    },
                    {
                        value:"11",
                        checked:false
                    },
                    {
                        value:"12",
                        checked:false
                    },
                ]
            }
        },
        created() {
            let timing = uni.getStorageSync("timing")
            let that = this
            if(timing.birthday_month){
                let tem = timing.birthday_month.split(",")
                console.log(tem)
                that.array.forEach((val,index) => {
                    if(tem.indexOf(val.value) != -1){
                        val.checked = true
                    }else{
                        val.checked = false
                    }
                })
            }else{
                timing.birthday_month = ""
            }
        },
        methods: {
            changeTab(e){
                let str = ""
                let tem = []
                let timing = uni.getStorageSync("timing")
                this.array[e].checked = !this.array[e].checked
                this.array.forEach((val,index) => {
                    if(val.checked == true){
                        tem.push(val.value)
                    }
                })
                
                tem.forEach((val,index) => {
                    if(index == tem.length -1){
                        str+=val
                    }else{
                        str += val + ","
                    }
                })
                timing.birthday_month = str
                uni.setStorageSync("timing",timing)
            }
        }
    }
</script>

<style lang="scss">
    .title{
        display: flex;
        align-items: center;
        padding: 60upx 40upx 40upx;
        font-size: 32upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        
        .fu{
            color: #AAAAAA !important;
            margin-left: 32upx;
        }
    }
    
    .item {
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 28upx 38upx;
        border-bottom: 2upx solid #EAEAEA;
    
        .itemLeft {
            margin-right: 28upx;
        }
    
        .unselect {
            width: 40upx;
            height: 40upx;
            background: #FFFFFF;
            opacity: 1;
            box-sizing: border-box;
            border: 2upx solid #707070;
            border-radius: 50%;
        }
    
        .selected {
            width: 40upx;
            height: 40upx;
            background: #FFFFFF;
            border: 2upx solid #1A73E8;
            border-radius: 50%;
            box-sizing: border-box;
            padding: 6upx;
    
            .fill {
                width: 100%;
                height: 100%;
                background: #1A73E8;
                border-radius: 50%;
            }
        }
    
    }
</style>
